import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as r,b as s}from"./app-28e2c6cf.js";const t={},i=s('<h1 id="面试-jvm" tabindex="-1"><a class="header-anchor" href="#面试-jvm" aria-hidden="true">#</a> 面试-JVM</h1><h3 id="jvm内存分析-解释下堆和栈" tabindex="-1"><a class="header-anchor" href="#jvm内存分析-解释下堆和栈" aria-hidden="true">#</a> JVM内存分析，解释下堆和栈</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JVM内存分析，解释下堆和栈</b></summary><p><b style="color:#f19977;">答：JVM内存结构主要分为堆内存、方法区和栈。<br>1. 堆内存是JVM中最大的一块内存地址。所有new出来的对象都存储在该区域。<br>2. 栈就是暂存数据的地方，栈中只保存基础数据类型的对象和自定义对象的引用，每个栈中的数据都是私有的，其它栈不能访问。<br>3. 方法区存放了要加载的类的信息如类名、修饰符、静态变量、构造函数等</b></p></details><h3 id="类加载机制" tabindex="-1"><a class="header-anchor" href="#类加载机制" aria-hidden="true">#</a> 类加载机制</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：类加载机制</b></summary><p><b style="color:#f19977;">答：<br>1. 加载：找到.class文件把文件的二进制字节流读进内存<br>2. 验证：保证加载的字节码是合法、安全、符合JVM规范的<br>3. 准备：为类的静态变量分配内存，并设置默认初始值<br>4. 解析：把符号引用替换成直接内存地址引用<br>5. 初始化：执行类构造器</b></p></details><h3 id="类的初始化过程" tabindex="-1"><a class="header-anchor" href="#类的初始化过程" aria-hidden="true">#</a> 类的初始化过程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：类的初始化过程</b></summary><p><b style="color:#f19977;">答：加载Class文件进内存，为静态变量分配内存并赋值，执行静态代码块。</b></p></details><h3 id="对象的初始化过程" tabindex="-1"><a class="header-anchor" href="#对象的初始化过程" aria-hidden="true">#</a> 对象的初始化过程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：对象的初始化过程</b></summary><p><b style="color:#f19977;">答：分配内存并为成员变量赋默认值，执行成员变量赋值和构造代码块，最后执行构造方法。</b></p></details><h3 id="父类加子类初始化过程" tabindex="-1"><a class="header-anchor" href="#父类加子类初始化过程" aria-hidden="true">#</a> 父类加子类初始化过程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：父类加子类初始化过程</b></summary><p><b style="color:#f19977;">答：<br>1. 父类静态变量 + 静态代码块<br>2. 子类静态变量 + 静态代码块<br>3. 父类成员变量 + 构造代码块 + 父类构造方法<br>4. 子类成员变量 + 构造代码块 + 子类构造方法</b></p></details><h3 id="对象什么时候可以被垃圾器回收" tabindex="-1"><a class="header-anchor" href="#对象什么时候可以被垃圾器回收" aria-hidden="true">#</a> 对象什么时候可以被垃圾器回收</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：对象什么时候可以被垃圾器回收</b></summary><p><b style="color:#f19977;">答：如果一个或多个对象没有任何引用指向它了，那么这个对象现在就是垃圾，则有可能会被垃圾回收器回收。对象与所有 GC Roots 之间没有任何引用链的会被回收。</b></p></details><h3 id="jvm垃圾回收算法有哪些" tabindex="-1"><a class="header-anchor" href="#jvm垃圾回收算法有哪些" aria-hidden="true">#</a> JVM垃圾回收算法有哪些</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JVM垃圾回收算法有哪些</b></summary><p><b style="color:#f19977;">答：<br>1. 标记清除算法：根据可达性分析算法得出的垃圾进行标记，对这些标记为可回收的内容进行垃圾回收。<br>2. 标记整理算法：和标记清除算法一样，将存活对象都向内存另一端移动，然后清理边界以外的垃圾。<br>3. 复制算法：将原有的内存空间一分为二，每次只用其中的一块，正在使用的对象复制到另一个内存空间中，然后将内存空间清空，交换两个内存角色，完成垃圾的回收。</b></p></details><h3 id="jvm有哪些垃圾回收器" tabindex="-1"><a class="header-anchor" href="#jvm有哪些垃圾回收器" aria-hidden="true">#</a> JVM有哪些垃圾回收器</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JVM有哪些垃圾回收器</b></summary><p><b style="color:#f19977;">答：<br>1. 串行垃圾收集器<br>2. 并行垃圾收集器(默认垃圾回收器)<br>3. GMS并发垃圾收集器<br>4. G1垃圾收集器</b></p></details><h3 id="cpu飙高排查方案与思路" tabindex="-1"><a class="header-anchor" href="#cpu飙高排查方案与思路" aria-hidden="true">#</a> CPU飙高排查方案与思路</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：CPU飙高排查方案与思路</b></summary><p><b style="color:#f19977;">答：使用top命令查看占用CPU情况并拿到进程ID，然后再查看进程中的线程占用CPU信息，并拿到占用较高线程的ID，再根据线程ID找到有问题代码的源码行号。</b></p></details>',19),l=[i];function d(c,o){return e(),r("div",null,l)}const n=a(t,[["render",d],["__file","面试-JVM.html.vue"]]);export{n as default};
